export function getAllVocabulary() {
  return week26.days.flatMap((day, dayIndex) =>
    day.vocabulary.map((word, wordIndex) => ({
      ...word,
      id: `w26-d${dayIndex + 1}-${wordIndex}`,
      dayId: day.id,
      dayTitle: day.title,
    }))
  )
}
